<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import MesLayout from '@/layouts/MesLayout.vue'
import { get } from '@/api/client'
type BoardRow = Record<string, unknown> & { id?: string | number }
const rows = ref<BoardRow[]>([]); const loading = ref(false); const error = ref('')
const value = (row: BoardRow, ...keys: string[]) => String(keys.map((key) => row[key]).find((item) => item !== undefined && item !== null) ?? '-')
const number = (row: BoardRow, ...keys: string[]) => Number(keys.map((key) => row[key]).find((item) => item !== undefined) ?? 0)
const lines = computed(() => rows.value.slice(0, 6))
async function load() { loading.value = true; error.value = ''; try { const response = await get<unknown>('/report/boards/workshop'); rows.value = Array.isArray(response) ? response as BoardRow[] : Array.isArray((response as { records?: unknown })?.records) ? (response as { records: BoardRow[] }).records : [] } catch (reason) { rows.value=[]; error.value=reason instanceof Error ? reason.message : '车间看板加载失败' } finally { loading.value=false } }
onMounted(load)
</script>
<template><MesLayout active="shopfloor"><header class="app-header"><div class="header-breadcrumb"><span>生产管理</span><span class="bc-sep">/</span><span class="bc-current">车间看板</span></div><div class="header-actions"><button class="btn btn-secondary btn-sm" :disabled="loading" @click="load">刷新</button><span class="user-avatar">张</span></div></header><main class="app-main" data-od-id="shopfloor-main"><h1 class="page-title">车间作业看板</h1><div class="kpi-grid shopfloor-kpis"><div class="kpi-card accent-border"><span class="kpi-label">在产产线</span><span class="kpi-value" v-count-up>{{ lines.length }}</span><span class="kpi-change">来自实时车间看板</span></div><div class="kpi-card"><span class="kpi-label">当前产量</span><span class="kpi-value" v-count-up>{{ rows.reduce((sum, row) => sum + number(row, 'outputQty', 'completedQty'), 0) }}</span><span class="kpi-change">实时汇总</span></div></div><div v-if="error" class="alert alert-error mb-5"><span class="alert-icon">!</span>{{ error }}</div><section class="card mb-5"><div class="card-header"><h2 class="card-title">产线状态</h2></div><div class="shopfloor-lines"><div v-if="loading" class="text-muted">正在加载...</div><div v-else-if="!lines.length" class="text-muted">暂无车间实时数据</div><article v-for="(line, index) in lines" :key="line.id ?? index" class="shopfloor-line"><div class="flex justify-between items-center mb-3"><span class="card-title">{{ value(line, 'lineName', 'workshopName') }}</span><span class="badge badge-status-ok"><span class="badge-dot"></span>{{ value(line, 'status') }}</span></div><div class="text-muted mb-3" style="font-size:var(--text-small)">{{ value(line, 'workOrderNo', 'productName') }}</div><div class="mb-2"><span class="text-muted">产量 {{ value(line, 'outputQty', 'completedQty') }}</span></div><div class="progress-bar" style="height:8px;margin-bottom:var(--space-2)"><div class="progress-fill" :style="{ width: `${Math.min(100, number(line, 'progress', 'completionRate'))}%` }"></div></div><div class="text-muted" style="font-size:var(--text-caption)">车间实时数据</div></article></div></section><section class="card"><div class="card-header"><h2 class="card-title">产线明细</h2></div><div class="data-table-wrap"><table class="data-table"><thead><tr><th>车间</th><th>产线</th><th>当前任务</th><th>产量</th><th>状态</th></tr></thead><tbody><tr v-if="!loading && !rows.length"><td colspan="5">暂无数据</td></tr><tr v-for="(row, index) in rows" :key="row.id ?? index"><td>{{ value(row, 'workshopName') }}</td><td class="cell-mono">{{ value(row, 'lineName', 'lineCode') }}</td><td>{{ value(row, 'workOrderNo', 'productName') }}</td><td>{{ value(row, 'outputQty', 'completedQty') }}</td><td><span class="badge badge-status-ok"><span class="badge-dot"></span>{{ value(row, 'status') }}</span></td></tr></tbody></table></div></section></main><footer class="app-statusbar"><span class="statusbar-item"><span class="dot ok"></span>系统正常</span><span class="statusbar-sep">|</span><span class="statusbar-item">车间看板 · {{ rows.length }} 条产线数据</span></footer></MesLayout></template>
<style scoped>.shopfloor-kpis{grid-template-columns:repeat(2,1fr);max-width:calc(50% - var(--space-3))}.shopfloor-lines{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:var(--space-4)}.shopfloor-line{background:var(--surface);border-radius:var(--radius);padding:var(--space-4)}@media(max-width:960px){.shopfloor-lines{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:720px){.shopfloor-kpis,.shopfloor-lines{grid-template-columns:1fr;max-width:none}}</style>
